namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        for (int i = 0; i < 5; i++)
        {
            _notifications.Add(new Notification(
                _nextId++,
                $"Welcome notification #{i + 1}",
                DateTime.UtcNow.AddMinutes(-10 + i)));
        }
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns notifications added after the given ID.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateNewNotification()
    {
        lock (_lock)
        {
            _notifications.Add(new Notification(
                _nextId,
                $"New event at {DateTime.UtcNow:HH:mm:ss} (#{_nextId})",
                DateTime.UtcNow));
            _nextId++;
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

<ul class="list-group">
    @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
    {
        <li class="list-group-item">
            <strong>@n.Message</strong>
            <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
        </li>
    }
</ul>

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Runs during prerender AND on interactive connect.
        // Load initial data so it appears in the server-rendered HTML.
        _notifications = NotificationService.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live and interactive
            // (it does NOT fire during static SSR/prerender), so this is safe.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate a new notification arriving on the service side
            NotificationService.SimulateNewNotification();

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(() =>
                {
                    _notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

